# Write-CanonFiles5.ps1 — Creates D1.4 discovery/analysis scripts for all 3 specs
# Run from: C:\Users\whale\git\uiao\tools\
# Usage:    powershell -ExecutionPolicy Bypass -File .\Write-CanonFiles5.ps1

$ErrorActionPreference = "Stop"
$repoRoot = "C:\Users\whale\git\uiao"

if (-not (Test-Path $repoRoot)) {
    Write-Error "Repo root not found: $repoRoot"
    return
}


# --- Spec 1 D1.4 — Authentication Protocol Audit ---
$b64_0 = ""

$path_0 = Join-Path $repoRoot "tools\discovery\Spec1-D1.4-Get-AuthenticationProtocolAudit.ps1"
$dir_0  = Split-Path $path_0 -Parent
if (-not (Test-Path $dir_0)) { New-Item -Path $dir_0 -ItemType Directory -Force | Out-Null }
$bytes_0 = [System.Convert]::FromBase64String($b64_0)
[System.IO.File]::WriteAllBytes($path_0, $bytes_0)
Write-Host "  OK  $path_0" -ForegroundColor Green

# --- Spec 2 D1.4 — HR-to-AD Attribute Mapping Matrix ---
$b64_1 = ""

$path_1 = Join-Path $repoRoot "tools\discovery\Spec2-D1.4-New-HRToADAttributeMappingMatrix.ps1"
$dir_1  = Split-Path $path_1 -Parent
if (-not (Test-Path $dir_1)) { New-Item -Path $dir_1 -ItemType Directory -Force | Out-Null }
$bytes_1 = [System.Convert]::FromBase64String($b64_1)
[System.IO.File]::WriteAllBytes($path_1, $bytes_1)
Write-Host "  OK  $path_1" -ForegroundColor Green

# --- Spec 3 D1.4 — IIS Application Pool Identity Audit ---
$b64_2 = ""

$path_2 = Join-Path $repoRoot "tools\discovery\Spec3-D1.4-Get-IISAppPoolIdentityAudit.ps1"
$dir_2  = Split-Path $path_2 -Parent
if (-not (Test-Path $dir_2)) { New-Item -Path $dir_2 -ItemType Directory -Force | Out-Null }
$bytes_2 = [System.Convert]::FromBase64String($b64_2)
[System.IO.File]::WriteAllBytes($path_2, $bytes_2)
Write-Host "  OK  $path_2" -ForegroundColor Green


Write-Host "`nAll 3 D1.4 files written. Now run:" -ForegroundColor Cyan
Write-Host "  cd C:\Users\whale\git\uiao" -ForegroundColor White
Write-Host "  git add tools/discovery/Spec1-D1.4-Get-AuthenticationProtocolAudit.ps1" -ForegroundColor White
Write-Host "  git add tools/discovery/Spec2-D1.4-New-HRToADAttributeMappingMatrix.ps1" -ForegroundColor White
Write-Host "  git add tools/discovery/Spec3-D1.4-Get-IISAppPoolIdentityAudit.ps1" -ForegroundColor White
Write-Host @"
  git commit -m "feat(discovery): add D1.4 scripts for all 3 priority specs

    Spec 1 D1.4: Authentication Protocol Audit
      - 6-pass scan: unconstrained delegation, KCD, RBCD, protocol
        transition, cert-based machine auth, NTLM dependency indicators
      - Delegation chain graph, risk classification, JSON+CSV output

    Spec 2 D1.4: HR-to-AD Attribute Mapping Matrix
      - 22+ canonical HR->AD attribute mappings across 8 sections
      - AD population rate audit, coexistence flow analysis
      - OrgPath mapping per ADR-048, gap analysis
      - JSON + Markdown specification output

    Spec 3 D1.4: IIS Application Pool Identity Audit
      - IIS server discovery via HTTP/ SPN and OU search
      - Remote WinRM config collection (WebAdministration + appcmd fallback)
      - Domain account resolution with delegation/SPN/group analysis
      - App pool -> site -> auth dependency mapping
      - Risk classification, D1.1 cross-reference, JSON+CSV output

    Ref: UIAO_136, ADR-003, ADR-004, ADR-048"
"@ -ForegroundColor White
Write-Host "  git push origin main" -ForegroundColor White
